import math

MOD = 10**9 + 7

def main():
    n = int(sys.stdin.readline())
    a = list(map(int, sys.stdin.readline().split()))

    # Precompute gcd(i, j) for all pairs
    # Since gcd(i, j) = gcd(j, i), we can optimize
    gcd_ij = [[0] * (n+1) for _ in range(n+1)]
    for i in range(1, n+1):
        for j in range(1, n+1):
            gcd_ij[i][j] = math.gcd(i, j)

    # Precompute gcd(a_i, a_j) for all pairs
    gcd_a = [[0] * n for _ in range(n)]
    for i in range(n):
        for j in range(n):
            gcd_a[i][j] = math.gcd(a[i], a[j])

    # Calculate the prettiness value
    result = 0
    for i in range(n):
        for j in range(n):
            result = (result + gcd_a[i][j] * gcd_ij[i+1][j+1]) % MOD

    print(result)

