import math

MOD = 10**9 + 7

def main():
    n = int(sys.stdin.readline())
    a = list(map(int, sys.stdin.readline().split()))

    # Precompute gcd counts for i and j
    from collections import defaultdict
    gcd_i = defaultdict(int)
    gcd_a = defaultdict(int)

    for i in range(1, n+1):
        for j in range(1, n+1):
            gcd_i[math.gcd(i, j)] += 1

    for ai in a:
        for aj in a:
            gcd_a[math.gcd(ai, aj)] += 1

    # Multiply the counts and sum
    result = 0
    for g_i in gcd_i:
        for g_a in gcd_a:
            result = (result + g_i * g_a * gcd_i[g_i] * gcd_a[g_a]) % MOD

    print(result)

if __name__ == "__main__":
    main()

